from typing import List
import math

class Solution:
    def minTime(self, n: int, k: int, m: int, time: List[int], mul: List[float]) -> float:
        memo = {}

        def dp(stage, mask):
            if mask == 0:
                return 0
            if (stage, mask) in memo:
                return memo[(stage, mask)]

            ans = float('inf')
            for i in range(1 << n):
                if i & mask == i:
                    group_size = bin(i).count('1')
                    if group_size > k:
                        continue
                    max_time = max(time[j] for j in range(n) if (i & (1 << j)))
                    crossing_time = max_time * mul[stage]
                    new_stage = (stage + math.floor(crossing_time) % m) % m
                    if group_size < k and n - bin(mask).count('1') > 0:
                        continue
                    if group_size == k and n - bin(mask).count('1') == 0:
                        ans = min(ans, crossing_time)
                    else:
                        return_time = time[time.index(max_time)] * mul[new_stage]
                        new_stage_return = (new_stage + math.floor(return_time) % m) % m
                        ans = min(ans, crossing_time + return_time + dp(new_stage_return, mask ^ i))
            memo[(stage, mask)] = ans
            return ans

        ans = dp(0, (1 << n) - 1)
        if ans == float('inf'):
            return -1
        return ans
